float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


     rand_preset = max(.2,min(.85,rand_preset));
    vec2 uv_zero = vUv;
    vec2 uv2 = vec2( floor(vUv.x*10), floor(vUv.y*10) )*0.1
               + rand_preset.xy;
    vec4 N = texture( sampler_pw_noise_lq, uv2 * uAspect.xy );
    vUv += N.xy;

    ret = mix(0,rand_preset.xxx*(1.5,-.5,0),GetPixel(fract(vUv)).x);
    ret -= mix(ret,rand_preset*vec3(0,1.5,.5),GetBlur1(fract(vUv)).y);
    ret -= mix(ret,rand_preset*vec3(1.8,.5,2),GetBlur2(fract(vUv)).z);
    ret = mix(ret,rand_preset.yyy*vec3(-.45,.25,.5),GetPixel(fract(vUv)).y);
    ret = mix(ret,rand_preset.zzz*vec3(1.15,.75,-.2),GetPixel(fract(vUv)).z);
    ret -= mix(-ret,.75,GetPixel(uv_zero).xzy-.125);
    ret = pow(ret,rand_preset-ret);
    ret *= ret;

  fragColor = ret;
}
